// A concrete table of growth rates side by side.
// Big O is an upper bound — you can always quote a LOOSER one and be correct.

const pairs = [
  ['f(n) = 3n + 5',     'O(n)',      'Ω(n)',      'Θ(n)',      'o(n²)'],
  ['f(n) = n²',          'O(n²)',     'Ω(n²)',     'Θ(n²)',     'o(n³)'],
  ['f(n) = log n',       'O(log n)',  'Ω(1)',      '—',         'o(n)'],
  ['f(n) = n²',          'O(n³)',     '— (loose)', '—',         '— (n² ≠ o(n²))'],
];

console.log('Function              | Tight O      | Tight Ω      | Θ?            | Little-o');
console.log('----------------------+--------------+--------------+---------------+----------');
for (const row of pairs) {
  console.log(row.map((c, i) => c.padEnd(i === 0 ? 21 : 13)).join(' | '));
}

// Note row 4: any function is O of something bigger, but it's only Θ of itself.
// Saying 'n² = O(n³)' is correct but loose — and n² is NOT o(n²),
// because little-o requires a STRICT separation.
